export const theme = {
  colors: {
    primary: "#000000",
    background: "#FFFFFF",
    secondaryBackground: "#F5F5F7",
    border: "#E5E5EA",
    textPrimary: "#000000",
    textSecondary: "#8E8E93",
    buttonText: "#FFFFFF",
  },
  typography: {
    heroTitle: {
      size: 28,
      weight: "900",
      letterSpacing: -0.5,
    },
    sectionTitle: {
      size: 22,
      weight: "800",
    },
    cardTitle: {
      size: 16,
      weight: "700",
    },
    price: {
      size: 18,
      weight: "900",
    },
    body: {
      size: 14,
      weight: "400",
    },
    caption: {
      size: 12,
      weight: "400",
    },
  },
  radius: {
    card: 22,
    button: 18,
    input: 18,
    chip: 30,
  },
};

export const layout = {
  padding: 18,
  spacing: 16,
  radius: theme.radius,
};
